exercises.solution_code:
#include <iostream>

int main() {
    int code{};
    std::cin >> code;

    if (code == 0) {
        std::cout << "Success\n";
    }
    else if (code >= 1 && code <= 9) {
        std::cout << "Recoverable error: " << code << '\n';
    }
    else if (code >= 10) {
        std::cout << "Fatal error: " << code << '\n';
    }
    else {
        std::cout << "Invalid code\n";
    }

    return 0;
}

