exercises.solution_code:
#include <cstdlib>
#include <iostream>

void guardDivisor(int divisor) {
    if (divisor == 0) {
        std::cout << "Error: division by zero\n";
        std::exit(EXIT_SUCCESS);
    }
}

int main() {
    int a{};
    int b{};
    std::cin >> a >> b;

    guardDivisor(b);

    std::cout << a / b << '\n';

    return EXIT_SUCCESS;
}
